  {atab==="dash"&&<div className="space-y-6"><div className="bg-gradient-to-r from-slate-900 via-purple-900 to-slate-900 rounded-3xl p-8 text-white relative overflow-hidden"><div className="absolute inset-0 opacity-20"><div className="absolute top-0 right-0 w-96 h-96 bg-purple-500 rounded-full blur-3xl"/></div><div className="relative z-10"><h1 className="text-3xl font-black mb-2 text-white">PocketBite Admin 👑</h1><p className="text-white/80">Full platform overview and management</p></div></div><div className="grid sm:grid-cols-4 gap-4">{[{l:"Restaurants",v:rests.length,i:"🏪"},{l:"Users",v:users.length,i:"👥"},{l:"Bookings",v:bks.length,i:"🎫"},{l:"Revenue",v:`KES ${totalRev.toLocaleString()}`,i:"💎"}].map(s=><div key={s.l} className="bg-white rounded-3xl p-5 shadow-lg border border-gray-100"><div className="w-12 h-12 rounded-2xl bg-gray-900 flex items-center justify-center text-2xl mb-3 shadow-md">{s.i}</div><p className="text-2xl font-black text-gray-900">{s.v}</p><p className="text-sm text-gray-600">{s.l}</p></div>)}</div><div className="grid lg:grid-cols-2 gap-6"><div className="bg-white rounded-3xl p-6 shadow-lg border border-gray-100"><h3 className="font-black text-xl mb-4">Recent Bookings</h3><div className="space-y-3 max-h-72 overflow-y-auto">{bks.slice(-6).reverse().map(bk=><div key={bk.id} className="flex justify-between p-3 bg-gray-50 rounded-xl"><div><p className="font-bold text-sm">{bk.dn} → {bk.rn}</p><p className="text-[11px] text-gray-500">{bk.dt} • {bk.st}</p></div><span className={`px-2 py-1 rounded-full text-[10px] font-bold h-fit ${bk.st==="confirmed"?"bg-green-100 text-green-700":"bg-amber-100 text-amber-700"}`}>{bk.st.toUpperCase()}</span></div>)}</div></div><div className="bg-white rounded-3xl p-6 shadow-lg border border-gray-100"><h3 className="font-black text-xl mb-4 text-gray-900">Top Performing Restaurants 🏆</h3><div className="space-y-4">{top5.map((r,i)=><div key={r.id} className="flex items-center gap-3 p-2 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors"><span className="font-black text-gray-300 w-8 text-center">#{i+1}</span><img src={r.img} className="w-12 h-12 rounded-lg object-cover shadow-sm"/><div className="flex-1"><p className="font-bold text-sm text-gray-900">{r.n}</p><p className="text-[11px] text-gray-500">{r.cui} • {r.cat}</p></div><span className="text-sm font-bold text-pink-600">❤️ {r.lk}</span></div>)}</div></div></div></div>}
  {atab==="rests"&&<div><div className="flex justify-between items-center mb-6"><h2 className="text-2xl font-black">🏪 Platform Restaurants ({rests.length})</h2><button onClick={()=>{const n=prompt("Name?"); if(n) setRests(p=>[...p, {...IR[0], id:"r"+Date.now(), n}])}} className="px-4 py-2 bg-emerald-600 text-white rounded-xl font-bold shadow-md hover:bg-emerald-700 transition-all">+ Add Spot</button></div><div className="bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden"><div className="overflow-x-auto"><table className="w-full"><thead><tr className="border-b bg-gray-50"><th className="text-left px-4 py-3 text-xs font-black text-gray-500 uppercase">Restaurant</th><th className="text-left px-4 py-3 text-xs font-black text-gray-500 uppercase">Category</th><th className="text-left px-4 py-3 text-xs font-black text-gray-500 uppercase">Stats</th><th className="text-left px-4 py-3 text-xs font-black text-gray-500 uppercase">Actions</th></tr></thead><tbody>{rests.map(r=><tr key={r.id} className="border-b border-gray-50 hover:bg-gray-50 transition-colors"><td className="px-4 py-3"><div className="flex items-center gap-3"><img src={r.img} className="w-10 h-10 rounded-lg object-cover shadow-sm"/><span className="font-bold text-sm text-gray-900">{r.n}</span></div></td><td className="px-4 py-3"><span className={`text-[10px] px-2 py-1 rounded-full font-black uppercase tracking-wider ${r.cat==="local"?"bg-green-100 text-green-700":r.cat==="formal"?"bg-purple-100 text-purple-700":"bg-orange-100 text-orange-700"}`}>{r.cat}</span></td><td className="px-4 py-3 text-sm font-medium"><div className="flex gap-3"><span>❤️ {r.lk}</span><span>⭐ {r.rt}</span></div></td><td className="px-4 py-3"><div className="flex gap-2"><button onClick={() => setShowRestModal(r)} className="px-3 py-1.5 bg-blue-50 text-blue-600 rounded-lg text-xs font-black uppercase hover:bg-blue-100 transition-all">Edit</button><button onClick={() => { if(confirm("Remove?")) setRests(p=>p.filter(x=>x.id!==r.id)); }} className="px-3 py-1.5 bg-red-50 text-red-600 rounded-lg text-xs font-black uppercase hover:bg-red-100 transition-all">Del</button></div></td></tr>)}</tbody></table></div></div></div>}
